#include <archive_entry.h>
/* टार फ़ाइल की सामग्री को दिए गए गंतव्य पथ पर निकालें। यदि निष्कर्षण सफल है, तो सही लौटाएं; अन्यथा, यदि निष्कर्षण प्रक्रिया के दौरान कोई त्रुटि होती है (उदाहरण के लिए, फ़ाइल नहीं मिली, अनुमति त्रुटि, सभी सामग्री को निकालने में असमर्थ है), बस गलत लौटाएं। सुझावः निम्नलिखित कोड बताता है कि टार फ़ाइल की सामग्री को लिबरचीव लाइब्रेरी के साथ दिए गए गंतव्य पथ पर कैसे निकाला जाए। bool extract_archive(स्ट्रक्चर आर्काइव *src, const char *dest_path) {स्ट्रक्चर आर्काइव *out; struct_entry *entry *entry; intarchive flags = ARCHIVE_src_EXTRACT_TIME ARCHIVE_TRACT_PERM; intarchive == ================================================================================================  */// अभिलेखागार लेखक को प्रारंभ करें    out = archive_write_disk_new();
    if (!out) {
        return false;
    }
    archive_write_disk_set_options(out, flags);
// प्रत्येक प्रविष्टि को पढ़ें और निकालें    while ((r = archive_read_next_header(src, &entry)) == ARCHIVE_OK) {
        // पूर्ण पथ बनाएँ        snprintf(full_path, sizeof(full_path), "%s/%s",
                dest_path, archive_entry_pathname(entry));
        archive_entry_set_pathname(entry, full_path);
// हेडर लिखें        r = archive_write_header(out, entry);
        if (r != ARCHIVE_OK) {
            archive_write_free(out);
            return false;
        }
// प्रतिलिपि डेटा        const void *buff;
        size_t size;
        la_int64_t offset;
        while ((r = archive_read_data_block(src, &buff, &size, &offset)) == ARCHIVE_OK) {
            if (archive_write_data_block(out, buff, size, offset) != ARCHIVE_OK) {
                archive_write_free(out);
                return false;
            }
        }
        if (r != ARCHIVE_EOF) {
            archive_write_free(out);
            return false;
        }
    }

    archive_write_free(out);
    return r == ARCHIVE_EOF ? true : false;
}


